  /* Когда меню открыто — фиксируем мобильную шапку и даём ей фон */
  body.mobile-menu-open .navbar-3 {
    position: fixed !important;
    top: 0;
    left: 0;
    right: 0;
    z-index: 1200 !important;
    transform: translateZ(0); /* страховка от глюков в FF */

    /* !!! тут поставь тот же фон, что у .header-container-2 !!! */
    background: #fff; /* пример, замени на свой цвет/градиент */
  }
</style>

<script>
/**
 * Mobile Webflow navbar — Firefox-safe:
 * - при открытии: фиксируем .navbar-3, считаем её высоту
 * - overlay и меню начинаются сразу под шапкой
 * - диммер #menuDimmer под меню
 * - скролл лочится через overflow, без position:fixed на body
 */
(function () {
  const NAVBAR = '.navbar-3';
  const BTN    = `${NAVBAR} .w-nav-button`;
  const OVSEL  = '.w-nav-overlay';
  const MENU   = '.w-nav-overlay .w-nav-menu';
  const MOBILE = '(max-width: 991px)';
  const isMobile = () => window.matchMedia(MOBILE).matches;

  // диммер
  let dimmer = document.getElementById('menuDimmer');
  if (!dimmer) {
    dimmer = document.createElement('div');
    dimmer.id = 'menuDimmer';
    document.body.appendChild(dimmer);
  }

  const $    = (s) => document.querySelector(s);
  const btn  = ()  => $(BTN);
  const ov   = ()  => $(OVSEL);
  const menu = ()  => $(MENU);
  const open = ()  => !!$(`${BTN}.w--open`);

  const lockScroll = () => {
    document.documentElement.style.overflow = 'hidden';
    document.body.style.overflow = 'hidden';
  };
  const unlockScroll = () => {
    document.documentElement.style.overflow = '';
    document.body.style.overflow = '';
  };

  function navHeight(){
    const el = $(NAVBAR);
    const h  = el ? Math.round(el.getBoundingClientRect().height) : 70;
    return h || 70;
  }

  function placeUnderHeader(){
    const h = navHeight();

    // гарантируем, что overlay в body (Firefox)
    const o = ov();
    if (o){
      if (o.parentNode !== document.body) document.body.appendChild(o);
      Object.assign(o.style, {
        position: 'fixed',
        top:      h + 'px',
        left:     '0',
        right:    '0',
        bottom:   '0',
        width:    '100%',
        overflow: 'visible',
        display:  'block',
        pointerEvents: 'auto'
      });
    }

    const m = menu();
    if (m){
      Object.assign(m.style, {
  position: 'fixed',
        top:       h + 'px',
        left:      '0',
        right:     '0',
      bottom:    '0',              // Растягиваем до низа
        overflowY: 'auto',           // Скролл только внутри меню
        maxHeight: 'none',           // Снимаем ограничения Webflow
        WebkitOverflowScrolling: 'touch' // Плавность на iOS
      });
    }

    dimmer.style.top = h + 'px';
  }

  function show(){
    if (!isMobile()) return;

    document.body.classList.add('mobile-menu-open');
    placeUnderHeader();

    dimmer.style.opacity       = '1';
    dimmer.style.pointerEvents = 'auto';

    lockScroll();
  }

function hide(){
  dimmer.style.opacity       = '0';
  dimmer.style.pointerEvents = 'none';

  document.body.classList.remove('mobile-menu-open');
  unlockScroll();

  const o = ov();
  if (o){ // ← убрали проверку !open()
    o.style.pointerEvents = 'none';
    o.style.display       = 'none';
    o.style.height        = ''; // сброс возможных залипаний FF
  }
}


  function sync(){
    if (!isMobile()) {
      hide();
      return;
    }
    if (open()) show(); else hide();
  }

  // клик по бургеру
  document.addEventListener('click', (e) => {
    if (e.target.closest(BTN)) {
      setTimeout(sync, 0);
    }
  });

  // клик по диммеру — закрываем меню
  dimmer.addEventListener('click', () => {
    const b = btn();
    if (b && b.classList.contains('w--open')) b.click();
  });

  // наблюдаем изменения классов/стилей от Webflow
  const mo = new MutationObserver(() => setTimeout(sync, 0));
  mo.observe(document.documentElement, {
    subtree: true,
    childList: true,
    attributes: true,
    attributeFilter: ['class', 'style', 'data-nav-menu-open']
  });

  // при ресайзе/скролле актуализируем позицию
  window.addEventListener('resize', () => {
    if (open()) placeUnderHeader();
    sync();
  }, { passive: true });

  window.addEventListener('scroll', () => {
    if (open()) placeUnderHeader();
  }, { passive: true });

  document.addEventListener('DOMContentLoaded', sync);
})();
</script>
<style>
  /* Глобальный стоп-кран:
     когда меню НЕ открыто (нет класса на body),
     оверлей полностью выключен и не ловит клики */
  body:not(.mobile-menu-open) .w-nav-overlay {
    display: none !important;
    pointer-events: none !important;
    height: auto !important;
  }

  /* Когда меню открыто — даём оверлею клики,
     чтобы работало само меню */
  body.mobile-menu-open .w-nav-overlay {
    pointer-events: auto !important;
  }
  

/* Улучшаем поведение скролла на мобильных */
body.mobile-menu-open .w-nav-overlay .w-nav-menu {
    -webkit-overflow-scrolling: touch;  /* Инерционный скролл для старых iOS */
}
</style></div></div><section class="section-card-wrapper top"><div data-w-id="619b4720-e0b8-b7fe-673d-93cb391ced91" style="opacity:0" class="section-card hero-card---120px-page"><div class="w-layout-blockcontainer container-default w-container"><div data-w-id="619b4720-e0b8-b7fe-673d-93cb391ced94" style="-webkit-transform:translate3d(0, 6%, 0) scale3d(1, 1, 1) rotateX(0) rotateY(0) rotateZ(0) skew(0, 0);-moz-transform:translate3d(0, 6%, 0) scale3d(1, 1, 1) rotateX(0) rotateY(0) rotateZ(0) skew(0, 0);-ms-transform:translate3d(0, 6%, 0) scale3d(1, 1, 1) rotateX(0) rotateY(0) rotateZ(0) skew(0, 0);transform:translate3d(0, 6%, 0) scale3d(1, 1, 1) rotateX(0) rotateY(0) rotateZ(0) skew(0, 0);opacity:0" class="inner-container _850px center"><div class="inner-container _600px---tablet center"><div class="center-content"><div class="w-layout-vflex inner-container _500px---mbl center"><div class="mg-top-small"><h1 class="display-10 mid text-light">Glossary</h1></div></div><div class="mg-top-small"><div class="inner-container _562px center"><div class="text-neutral-light"><p class="paragraph-37">The following is a list of common window terms to help you in your quest of researching windows.</p></div></div></div></div></div></div></div></div></section><section class="section pd-120px"><div class="w-layout-blockcontainer container-default w-container"><div class="grid-2-columns template-page-sidebar"><div id="w-node-c2ab8be9-0392-5953-3f0c-a815af27dc5a-facb1579" data-w-id="c2ab8be9-0392-5953-3f0c-a815af27dc5a" style="opacity:0" class="card template-pages---sticky-card"><ul role="list" class="template-pages---sidebar-navigation w-list-unstyled"><li class="template-pages---nav-item-wrapper"><a href="#styling" class="template-pages---nav-item-link">Window Replacement</a></li><li class="template-pages---nav-item-wrapper"><a href="#editing-pages" class="template-pages---nav-item-link">Energy Efficient windows</a></li><li class="template-pages---nav-item-wrapper"><a href="#useful-notes" class="template-pages---nav-item-link">Energy Star</a></li></ul></div><div id="w-node-_1f3e9af0-d259-eb3f-f215-95c56ed92e45-facb1579" data-w-id="1f3e9af0-d259-eb3f-f215-95c56ed92e45" style="opacity:0" class="card template-pages---text-card"><div id="styling"><h2 class="mg-bottom-small">Windows Replacement</h2><p class="paragraph-35">The thought of replacing all or most of your old windows with new ones can be daunting and understandably so. Replacing windows throughout your house could be expensive, not to mention inconvenient but don&#x27;t get too discouraged right away. With proper planning to ensure you install the right windows, ones that meet your needs, vision, and budget, this could be one of the best and most financially wise decisions of your life.</p><h4 class="mg-bottom-extra-small">Understand why window replacement is necessary.</h4><p class="paragraph-36">There are many reasons that people choose to replace old windows; Appearance, deterioration, maintenance and energy efficiency are just a few. Once you decide to purchase new windows for your home and the reason you are replacing them, you automatically narrow down your search, making it easier to reach a decision. Some materials may be better for energy efficiency, others because they fit in with the aesthetic of your home.</p><h4 class="mg-bottom-extra-small">Set a budget.</h4><p class="paragraph-38">Deciding on the number of windows you need to replace and setting a budget that works for you should be your next step. Windows are generally priced very differently; hence, the number of windows you will be replacing will help you determine the most economical style of window.</p><h4 class="mg-bottom-extra-small">Choose your style.</h4><p class="paragraph-39">The best way to start is to think about the rooms in which the windows will be placed. Do they face the front of the house or are they hidden at the back? It&#x27;s more than acceptable to use several styles throughout your home, keep in mind, however, that some windows need a little more maintenance than others. For example wood windows require a little more up-keep than <a href="https://bayareawindowpros.com/windows/material/vinyl">vinyl</a>, which are virtually maintenance free. However the aesthetic benefits of wood usually far out way the maintenance they need over the years, as always personal preference is key.</p><h4 class="mg-bottom-extra-small">How can I get more information?</h4><p class="paragraph-40">When you request a <a href="/">free quote</a> you will have a chance to learn more about your options and speak with a licensed home improvement professional. We&#x27;ll make sure that you have the information you need to make a well thought out decision that&#x27;s right for you.<br/></p></div><div class="divider mg-large"></div><div id="editing-pages"><h2 class="mg-bottom-small">Energy Efficient Windows</h2><h4 class="mg-bottom-extra-small">What are Green or Energy Efficient windows?</h4><p class="mg-bottom-default">Green or energy efficient, windows are windows that transmit the least amount of heat and reduce your home energy output. They also protect your home temperature from being affected by the external weather.<br/><br/>- Most of the heat loss in the home is caused by the windows, because of the type of glass and/or type of frame. This is because older windows, typically aluminum windows, are conductors meaning they transmit heat and cold.<br/>- Installing green windows into your home will not only maintain the desired temperature of your home but in the long run will save you money on heating and cooling bills. Windows that are considered &quot;green&quot; insulate your home and decrease heat transfer making your home more energy efficient.</p><h4 class="mg-bottom-extra-small">What determines energy efficiency of a window?</h4><p class="mg-bottom-default">The type of glass used for a window, determines its efficiency rate how much and what kind of light will be let in. <br/>- The newest technology for glass allows for a large reduction in heat loss. With a particular type of glass called &quot;Low-E,&quot; or low emissivity, energy efficiency becomes possible.<br/>- Low-E glass allows the visible light to enter the home, but blocks the bad light that damages skin and cause colors to fade. For the highest efficiency, the space between the panes is filled with argon gas to further insulate.<br/>- Warm edge spacers in between the panes also reduce heat transfer as well as insulate the edges creating a highly efficient &quot;green&quot; window.<br/>- For even greater efficiency, the frames of energy efficient windows are made with materials that also help reduce heat transfer while increasing insulation, like vinyl or fiberglass.<br/><br/>The circle graph above shows that one-quarter of your carbon footprint consists of home energy use, but this can vary depending on the kinds of energy sources available to power your home. ENERGY STAR calculates carbon savings for ENERGY STAR windows, doors, and skylights based on the mix of fuels in a region and the estimated energy use for a typical home.</p></div><div class="divider mg-large"></div><div id="useful-notes"><h2 class="mg-bottom-small">Energy Star</h2><p class="paragraph-41">ENERGY STAR is the trusted, government-backed symbol for energy efficiency helping us all save money and protect the environment through energy-efficient products and practices.<br/>‍<br/>The ENERGY STAR label was established to:Reduce greenhouse gas emissions and other pollutants caused by the inefficient use of energy; andMake it easy for consumers to identify and purchase energy-efficient products that offer savings on energy bills without sacrificing performance, features, and comfort.</p><h4 class="mg-bottom-extra-small">How Does EPA Choose which Products Earn the Label?</h4><p class="mg-bottom-default">Products can earn the ENERGY STAR label by meeting the energy efficiency requirements set forth in ENERGY STAR product specifications. EPA establishes these specifications based on the following set of key guiding principles:<br/>- Product categories must contribute significant energy savings nationwide.<br/>- Qualified products must deliver the features and performance demanded by consumers, in addition to increased energy efficiency.<br/>- If the qualified product costs more than a conventional, less-efficient counterpart, purchasers will recover their investment in increased energy efficiency through utility bill savings, within a reasonable period of time.<br/>- Energy efficiency can be achieved through broadly available, non-proprietary technologies offered by more than one manufacturer.<br/>- Product energy consumption and performance can be measured and verified with testing.<br/>- Labeling would effectively differentiate products and be visible for purchasers.<br/><br/>ENERGY STAR is the trusted, government-backed symbol for energy efficiency helping us all save money and protect the environment through energy-efficient products and practices.<br/><br/>The ENERGY STAR label was established to:<br/>- Reduce greenhouse gas emissions and other pollutants caused by the inefficient use of energy; <br/>- Make it easy for consumers to identify and purchase energy-efficient products that offer savings on energy bills without sacrificing performance, features, and comfort.</p><h4 class="mg-bottom-extra-small">How Does EPA Choose which Products Earn the Label?</h4><p class="paragraph-42">Products can earn the ENERGY STAR label by meeting the energy efficiency requirements set forth in ENERGY STAR product specifications. EPA establishes these specifications based on the following set of key guiding principles:<br/>- Product categories must contribute significant energy savings nationwide.<br/>- Qualified products must deliver the features and performance demanded by consumers, in addition to increased energy efficiency.<br/>- If the qualified product costs more than a conventional, less-efficient counterpart, purchasers will recover their investment in increased energy efficiency through utility bill savings, within a reasonable period of time.<br/>- Energy efficiency can be achieved through broadly available, non-proprietary technologies offered by more than one manufacturer.<br/>- Product energy consumption and performance can be measured and verified with testing.Labeling would effectively differentiate products and be visible for purchasers.</p></div></div></div></div></section><footer data-w-id="080cd6ed-2ec3-ab0f-3fec-cc4bec09a603" class="footer-wrapper"><div class="footer-top-cards-wrapper---pd"></div><div class="footer-card"><div class="w-layout-blockcontainer container-default w-container"><div class="footer-v1-content-wrapper"><div data-w-id="080cd6ed-2ec3-ab0f-3fec-cc4bec09a622" class="inner-container _420px _100-tablet"><div class="inner-container _400px---tablet _100-mbp"><div class="text-light"><div class="display-7 mid">Need Help? <br/>Call Us Now </div></div><div class="mg-top-small"><div class="text-neutral-light"><p class="paragraph-15">(650) 461-4446</p></div></div></div><div class="mg-top-small mg-top-16px---mbl"><div class="social-media-grid"><a href="https://www.facebook.com/" target="_blank" class="social-media-icon-wrapper-dark light w-inline-block"><div class="icon-font-social-media"></div></a><a href="https://www.instagram.com/" target="_blank" class="social-media-icon-wrapper-dark light w-inline-block"><div class="icon-font-social-media"></div></a></div></div></div><div id="w-node-_080cd6ed-2ec3-ab0f-3fec-cc4bec09a642-ec09a603" data-w-id="080cd6ed-2ec3-ab0f-3fec-cc4bec09a642" class="footer-v1---right-content"><div><div class="w-layout-grid footer-main-pages"><ul role="list" class="footer-column-links"><li class="footer-column-item"><a href="/about" class="footer-item-link w-inline-block"><div>About Us</div></a></li><li class="footer-column-item"><a href="/windows" class="footer-item-link w-inline-block"><div>Windows</div></a></li><li class="footer-column-item"><a href="#" class="footer-item-link w-inline-block"><div>Doors</div></a></li><li class="footer-column-item"><a href="/brand" class="footer-item-link w-inline-block"><div>Brands</div></a></li></ul><ul role="list" class="footer-column-links"><li class="footer-column-item"><a href="/glossary" aria-current="page" class="footer-item-link w-inline-block w--current"><div>Glossary</div></a></li><li class="footer-column-item"><a href="/contacts" class="footer-item-link w-inline-block"><div>Contacts Us</div></a></li><li class="footer-column-item"><a href="/testimonials" class="footer-item-link w-inline-block"><div>Testimonials</div></a></li><li class="footer-column-item"><a href="/financing" class="footer-item-link w-inline-block"><div>Financing</div></a></li></ul><ul id="w-node-_1ce59c11-5720-7953-47f7-4dd54673de6a-ec09a603" role="list" class="footer-column-links"><li class="footer-column-item"><a href="/faq" class="footer-item-link w-inline-block"><div>FAQs</div></a></li><li class="footer-column-item"><a href="/privacy-policy" class="footer-item-link w-inline-block"><div>Privacy Policy</div></a></li><li class="footer-column-item"><a href="/terms" class="footer-item-link w-inline-block"><div>Terms of Use</div></a></li></ul></div></div><p id="w-node-_49f8c755-3225-d40d-f9ab-cc9f4b368c44-ec09a603" class="paragraph">©2026 Deluxe Windows, Inc. <br/>All rights reserved.<br/></p></div><div id="w-node-_080cd6ed-2ec3-ab0f-3fec-cc4bec09a6ef-ec09a603" class="inner-container _380px _100-tablet"><div class="inner-container _450px---mbl"><div class="center-content---tablet"><div class="logo-wrapper v1"><a href="/" class="logo-link w-inline-block"><img src="https://cdn.prod.website-files.com/6841ddf8ace3d9d9facb14fd/686ad2b4b668ce59a9c25b0e_White.avif" alt="" sizes="(max-width: 719px) 100vw, 719px" srcset="https://cdn.prod.website-files.com/6841ddf8ace3d9d9facb14fd/686ad2b4b668ce59a9c25b0e_White-p-500.png 500w, https://cdn.prod.website-files.com/6841ddf8ace3d9d9facb14fd/686ad2b4b668ce59a9c25b0e_White.avif 719w"/></a></div></div></div></div></div></div></div></footer></div><script src="https://d3e54v103j8qbb.cloudfront.net/js/jquery-3.5.1.min.dc5e7f18c8.js?site=6841ddf8ace3d9d9facb14fd" type="text/javascript" integrity="sha256-9/aliU8dGd2tb6OSsuzixeV4y/faTqgFtohetphbbj0=" crossorigin="anonymous"></script><script src="https://cdn.prod.website-files.com/6841ddf8ace3d9d9facb14fd/js/webflow.schunk.172ec51a511480e2.js" type="text/javascript" integrity="sha384-qU8s0hexa7230yNvRC7SOXbAhsCCiiSAtnmgEod8Ssr0OB50VGzzWLiPDvmaspsW" crossorigin="anonymous"></script><script src="https://cdn.prod.website-files.com/6841ddf8ace3d9d9facb14fd/js/webflow.schunk.b35ad38f1af2d1dd.js" type="text/javascript" integrity="sha384-kPxhylkVGPto1495l5ywl0+XeOoRmw9z2/veWrv7DrZxLddZq3b5CSHy2Pbwu6QE" crossorigin="anonymous"></script><script src="https://cdn.prod.website-files.com/6841ddf8ace3d9d9facb14fd/js/webflow.edf23106.7ffc1f3e33d51fa2.js" type="text/javascript" integrity="sha384-wicn3eL0bgoqEmw1FcBYHYixtBTtjwr4B1GcFI4Kf5QwoQyupq1wtEgCOlE9CsW3" crossorigin="anonymous"></script><script>
(function () {

  /* ================================
     1. UTM CAPTURE (СРАЗУ)
  ================================= */
  const TRACK_PARAMS = [
    "utm_source","utm_medium","utm_campaign",
    "utm_term","utm_content","matchtype",
    "device","creative","gclid"
  ];

  const params = new URLSearchParams(window.location.search);
  const hasUtm = TRACK_PARAMS.some(p => params.get(p));

  if (hasUtm) {
    // Есть UTM в URL — перезаписываем чисто
    TRACK_PARAMS.forEach(param => {
      const value = params.get(param);
      if (value) {
        localStorage.setItem(`lead_param_${param}`, value);
      } else {
        localStorage.removeItem(`lead_param_${param}`);
      }
    });

  } else {
    // Нет UTM в URL — проверяем localStorage
    const hasSavedUtm = TRACK_PARAMS.some(p => localStorage.getItem(`lead_param_${p}`));

    if (!hasSavedUtm) {
      // Нет нигде — пишем SEO / organic / direct
      const ref = document.referrer || "";
      let searchEngine   = "";
      let organicKeyword = "";
      let refDomain      = "";

      try {
        if (ref) {
          const refUrl = new URL(ref);
          refDomain    = refUrl.hostname.replace(/^www\./, "");

          const SEO_ENGINES = {
            "google.com":     "google",
            "bing.com":       "bing",
            "yahoo.com":      "yahoo",
            "duckduckgo.com": "duckduckgo",
            "yandex.ru":      "yandex",
            "yandex.com":     "yandex",
            "baidu.com":      "baidu"
          };

          for (const [domain, name] of Object.entries(SEO_ENGINES)) {
            if (refDomain.includes(domain)) {
              searchEngine   = name;
              organicKeyword = refUrl.searchParams.get("q")
                || refUrl.searchParams.get("p")
                || refUrl.searchParams.get("query")
                || "(not provided)";
              break;
            }
          }
        }
      } catch(e) {}

      if (searchEngine) {
        localStorage.setItem("lead_param_utm_source", searchEngine);
        localStorage.setItem("lead_param_utm_medium", "organic");
        if (organicKeyword) localStorage.setItem("lead_param_utm_term", organicKeyword);
      } else if (refDomain && !refDomain.includes(window.location.hostname)) {
        localStorage.setItem("lead_param_utm_source", refDomain);
        localStorage.setItem("lead_param_utm_medium", "referral");
      } else {
        localStorage.setItem("lead_param_utm_source", "(direct)");
        localStorage.setItem("lead_param_utm_medium", "(none)");
      }
    }
    // Если hasSavedUtm — ничего не трогаем (first-touch)
  }

  if (!localStorage.getItem("lead_param_landing_page")) {
    localStorage.setItem("lead_param_landing_page", window.location.pathname);
  }


  /* ================================
     2. HIDDEN FIELDS (DOM READY)
  ================================= */
  function injectHiddenFields(form) {
    [...TRACK_PARAMS, "landing_page"].forEach(param => {
      if (!form.querySelector(`input[name="${param}"]`)) {
        const input = document.createElement("input");
        input.type = "hidden";
        input.name = param;
        input.value = localStorage.getItem(`lead_param_${param}`) || "";
        form.appendChild(input);
      }
    });
  }

  document.addEventListener("DOMContentLoaded", function () {
    document.querySelectorAll("form").forEach(injectHiddenFields);
  });


  /* ================================
     3. LAZY SYSTEM INIT
  ================================= */
  let lazyLoaded = false;

  function initLazy() {
    if (lazyLoaded) return;
    lazyLoaded = true;

    initDate();
    initForms();
    loadZoho();
  }

  window.addEventListener('scroll', initLazy, { once: true });
  window.addEventListener('click', initLazy, { once: true });
  setTimeout(initLazy, 4000);


  /* ================================
     4. DATE SCRIPT (LAZY)
  ================================= */
  function initDate() {
    const now = new Date();
    const lastDayDate = new Date(now.getFullYear(), now.getMonth() + 1, 0);

    const monthNames = [
      'January','February','March','April','May','June',
      'July','August','September','October','November','December'
    ];

    document.querySelectorAll('[data-last-day]').forEach(el => {
      const format = el.getAttribute('data-last-day');

      let text = '';
      const m = lastDayDate.getMonth() + 1;
      const d = lastDayDate.getDate();
      const y = lastDayDate.getFullYear();

      if (format === 'us-short') {
        text = `${m}/${d}/${String(y).slice(-2)}`;
      } else if (format === 'long') {
        text = `${monthNames[lastDayDate.getMonth()]} ${d}, ${y}`;
      }

      el.textContent = text;
    });
  }


  /* ================================
     5. FORM + IP + GOOGLE SHEETS
  ================================= */
  function initForms() {

    let ipData = {};
    let ipLoaded = false;

    function fetchIP() {
      return fetch('https://ipapi.co/json/')
        .then(r => r.json())
        .then(data => {
          ipLoaded = true;
          ipData = data;
        })
        .catch(() => ipLoaded = true);
    }

    function waitIP(timeout = 800) {
      return Promise.race([
        fetchIP(),
        new Promise(res => setTimeout(res, timeout))
      ]);
    }

    document.querySelectorAll('form').forEach(form => {

      form.addEventListener('submit', function () {

        waitIP().then(() => {

          const formData = new FormData(form);

          formData.append('ip_address', ipData.ip || '');
          formData.append('geo_location', ipData.city || '');

          const body = new URLSearchParams(formData);

          fetch('https://script.google.com/macros/s/AKfycbyJGhNROpBI8TUkGn9RtdNtIDxNjxsI52kyHgBtDIUauSEWgzVIqCFPic0-chwjxNxU/exec', {
            method: 'POST',
            body,
            keepalive: true
          });

          fetch('https://script.google.com/macros/s/AKfycbwp7eg4fm8OZtiHLjAFrbNyPaSyDjZWmfTJyhkiAZ2UsWYmE6l7euH9K0RtdgODH44Rmg/exec', {
            method: 'POST',
            body,
            keepalive: true
          });

        });

      });

    });
  }


  /* ================================
     6. ZOHO (LAZY)
  ================================= */
  function loadZoho() {
    const script = document.createElement('script');
    script.src = "https://salesiq.zohopublic.com/widget?wc=siqfe34762ee44eb77120f2a13c55fed7c0984ca603ae60aafcaf2adda4331dc65a";
    script.defer = true;
    document.body.appendChild(script);
  }

})();
</script>

